
CREATE TABLE Customers (
    customerId INT IDENTITY(1,1) PRIMARY KEY,
    firstName NVARCHAR(MAX),
    lastName NVARCHAR(MAX),
    email NVARCHAR(MAX),
    mobile NVARCHAR(MAX),
    city NVARCHAR(MAX),
    stateName NVARCHAR(MAX),
    zipCode NVARCHAR(MAX),
    addressLine NVARCHAR(MAX)
);
GO

CREATE TABLE Vendors (
    code NVARCHAR(50) PRIMARY KEY,
    name NVARCHAR(MAX),
    phone NVARCHAR(MAX),
    city NVARCHAR(MAX),
    state NVARCHAR(MAX),
    zip NVARCHAR(MAX),
    email NVARCHAR(MAX)
);
GO

CREATE TABLE StoneCodes (
    code NVARCHAR(50) PRIMARY KEY,
    stoneType NVARCHAR(MAX),
    color NVARCHAR(MAX)
);
GO

CREATE TABLE Transactions (
    transactionId INT IDENTITY(1,1) PRIMARY KEY,
    customerId INT,
    salesperson NVARCHAR(MAX),
    totalAmount FLOAT,
    status NVARCHAR(MAX),
    createdAt DATETIME DEFAULT GETDATE()
);
GO

CREATE TABLE TransactionItems (
    itemId INT IDENTITY(1,1) PRIMARY KEY,
    transactionId INT,
    sku NVARCHAR(MAX),
    description NVARCHAR(MAX),
    quantity INT,
    price FLOAT,
    FOREIGN KEY(transactionId) REFERENCES Transactions(transactionId)
);
GO

CREATE TABLE Orders (
    id INT IDENTITY(1,1) PRIMARY KEY,
    orderType NVARCHAR(MAX),
    special NVARCHAR(MAX),
    lastName NVARCHAR(MAX),
    firstName NVARCHAR(MAX),
    orderDate NVARCHAR(MAX),
    estYear NVARCHAR(MAX),
    shipDate NVARCHAR(MAX),
    cf NVARCHAR(MAX),
    ack NVARCHAR(MAX),
    esti NVARCHAR(MAX),
    po NVARCHAR(MAX),
    cnt NVARCHAR(MAX),
    rec NVARCHAR(MAX),
    st NVARCHAR(MAX),
    co NVARCHAR(MAX),
    salesPerson NVARCHAR(MAX),
    rush NVARCHAR(MAX),
    workbag NVARCHAR(MAX),
    currentStage NVARCHAR(MAX),
    stageDueDate NVARCHAR(MAX),
    vendor NVARCHAR(MAX),
    customerConfi NVARCHAR(MAX),
    item NVARCHAR(MAX),
    name NVARCHAR(MAX),
    saleDescription NVARCHAR(MAX)
);
GO

SET IDENTITY_INSERT Customers ON;
GO
GO
SET IDENTITY_INSERT Customers OFF;
GO

GO

GO

SET IDENTITY_INSERT Orders ON;
GO
GO
SET IDENTITY_INSERT Orders OFF;
GO

